def BetweenDateHoursLeftInclusive(TestDate: Float64, TestHour: Float64, StartDate: Float64, StartHour: Float64, EndDate: Float64, EndHour: Float64) -> Bool:
    var TestRatioOfDay: Float64 = TestHour / 60.0
    var StartRatioOfDay: Float64 = StartHour / 60.0
    var EndRatioOfDay: Float64 = EndHour / 60.0

    if startDate + StartRatioOfDay <= endDate + EndRatioOfDay: # StartDate <= EndDate
        return (startDate + StartRatioOfDay <= TestDate + TestRatioOfDay) and (TestDate + TestRatioOfDay <= endDate + EndRatioOfDay)
    # EndDate < StartDate
    return (endDate + EndRatioOfDay <= TestDate + TestRatioOfDay) and (TestDate + TestRatioOfDay <= startDate + StartRatioOfDay)

